const items = $input.all();
const body = items[0].json.body;
const data = body.data;

// Validacao do telefone
const telefone = (data.motoboy_telefone_e164 || '').toString().trim();
const telefoneValido = /^55\d{2}9\d{8}$/.test(telefone);

if (!telefoneValido) {
  return [{ json: { telefone: '', mensagem: '', erro: 'Telefone invalido ou ausente: ' + (data.motoboy_telefone || '(vazio)') + ' -> ' + telefone, enviar: false } }];
}

const order = data.order_number || '';
const clienteNome = data.cliente_nome || '';
const endereco = data.cliente_endereco || 'Endereco nao informado';
const totalNum = data.total ? Number(data.total).toFixed(2).replace('.', ',') : '0,00';
const pagamento = data.forma_pagamento || '';
const pagMap = { dinheiro: 'Dinheiro', cartao: 'Cartao', pix: 'PIX' };
const pagLabel = pagMap[pagamento] || pagamento;

const msg = '\ud83c\udfcd\ufe0f *Entrega Atribuida!*\n'
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n'
  + '\ud83d\udccb Pedido *#' + order + '*\n'
  + '\ud83d\udc64 Cliente: ' + clienteNome + '\n'
  + '\ud83d\udccd ' + endereco + '\n'
  + '\ud83d\udcb0 Valor: *R$ ' + totalNum + '*\n'
  + (pagLabel ? '\ud83d\udcb3 Pagamento: ' + pagLabel + '\n' : '')
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\n'
  + 'Dirija-se ao estabelecimento para retirar o pedido. \ud83d\ude80';

return [{ json: { telefone: telefone, mensagem: msg, enviar: true } }];
